class Solution:
    def getSmallestString(self, s: str, k: int) -> str:
        n = len(s)
        # dp[i][k] = smallest string for first i characters with total distance k
        dp = [[''] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = ''

        for i in range(1, n + 1):
            for dist in range(k + 1):
                if dp[i - 1][dist] != '':
                    # Try changing s[i-1] to any character
                    for c in range(ord('a'), ord('z') + 1):
                        cost = min(abs(c - ord(s[i - 1])), 26 - abs(c - ord(s[i - 1])))
                        if dist + cost <= k:
                            new_str = dp[i - 1][dist] + chr(c)
                            if dp[i][dist + cost] == '' or new_str < dp[i][dist + cost]:
                                dp[i][dist + cost] = new_str

        # Find the lexicographically smallest string among all possible distances
        result = min(dp[n][dist] for dist in range(k + 1) if dp[n][dist] != '')
        return result
